<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Categorías | Admin</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="/css/admin.css"><link rel="stylesheet" href="/css/alerts.css"></head><body><div class="wrapper d-flex"><?php include(__DIR__ . "/../../includes/sidebar.php"); ?><main class="main-content flex-grow-1 p-4"><?php include(__DIR__ . "/../../includes/topbar.php"); require_once(__DIR__ . "/../../includes/flash.php"); flash_render(); ?><div class="content-container-max mx-auto mt-4"><div class="card border-0 shadow-sm rounded-4 p-4 mb-4"><h1 class="h4 mb-3"><?= $edit['id'] ? 'Editar' : 'Nueva' ?> categoría</h1><form action="/php/controlador/categorias/guardar.php" method="post" class="row g-3"><input type="hidden" name="id" value="<?= (int)$edit['id'] ?>"><div class="col-md-5"><input class="form-control" name="nombre" required placeholder="Nombre" value="<?= htmlspecialchars($edit['nombre']) ?>"></div><div class="col-md-5"><input class="form-control" name="descripcion" placeholder="Descripción" value="<?= htmlspecialchars($edit['descripcion'] ?? '') ?>"></div><div class="col-md-2"><button class="btn btn-warning w-100">Guardar</button></div></form></div><div class="card border-0 shadow-sm rounded-4 p-4"><h2 class="h4">Categorías</h2><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Nombre</th><th>Descripción</th><th>Estado</th><th></th></tr></thead><tbody><?php while($c=$categorias->fetch_assoc()): ?><tr><td><?= htmlspecialchars($c['nombre']) ?></td><td><?= htmlspecialchars($c['descripcion'] ?? '') ?></td><td><form action="/php/controlador/categorias/estado.php" method="post"><input type="hidden" name="id" value="<?= $c['id'] ?>"><input type="hidden" name="estado" value="<?= $c['estado'] ? 0 : 1 ?>"><button class="btn btn-sm <?= $c['estado'] ? 'btn-success' : 'btn-secondary' ?>"><?= $c['estado'] ? 'Activa' : 'Inactiva' ?></button></form></td><td><a class="btn btn-outline-primary btn-sm" href="?editar=<?= $c['id'] ?>">Editar</a></td></tr><?php endwhile; ?></tbody></table></div></div></div></main></div></body></html>
